def hasPathSum(root, targetSum):
    def dfs(node, remaining):
        if node is None:
            return False
        remaining -= node.val
        if node.left is None and node.right is None:
            return remaining == 0
        return dfs(node.left, remaining) or dfs(node.right, remaining)

    return dfs(root, targetSum)

